/** IATA code → ISO country, expanded once at module init. */
export const IATA_CC: ReadonlyMap<string, string> = (() => {
  const m = new Map<string, string>()
  for (const [cc, s] of Object.entries(CC_CODES))
    for (let i = 0; i + 3 <= s.length; i += 3) m.set(s.slice(i, i + 3), cc)
  return m
})()
